import{_ as a,o as s,c as i,a2 as t}from"./chunks/framework.b3aQeZRM.js";const g=JSON.parse('{"title":"Setup Wizard","description":"","frontmatter":{},"headers":[],"relativePath":"model-setup.md","filePath":"model-setup.md"}'),n={name:"model-setup.md"};function l(o,e,d,p,r,c){return s(),i("div",null,[...e[0]||(e[0]=[t(`<h1 id="setup-wizard" tabindex="-1">Setup Wizard <a class="header-anchor" href="#setup-wizard" aria-label="Permalink to &quot;Setup Wizard&quot;">​</a></h1><p>Relay includes an interactive setup wizard and a headless CLI mode for agents and scripts.</p><h2 id="interactive-tui" tabindex="-1">Interactive (TUI) <a class="header-anchor" href="#interactive-tui" aria-label="Permalink to &quot;Interactive (TUI)&quot;">​</a></h2><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> run</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> setup</span></span></code></pre></div><p>Arrow keys to navigate, Enter to pick. The wizard:</p><ol><li>Auto-detects your GPU, VRAM, and RAM</li><li>Shows supported modes: local models, cloud API proxy, or BYO (existing server)</li><li>For local: picks models from the catalog, lets you download them, generates start scripts with optimal flags</li><li>For cloud: configures Gemini or other cloud APIs</li><li>Writes <code>.env</code> and start scripts</li></ol><p>Re-run <code>npm run setup</code> anytime to change models or settings. It preserves your existing <code>.env</code> values and only adds or updates what you change.</p><h2 id="the-sizing-engine" tabindex="-1">The Sizing Engine <a class="header-anchor" href="#the-sizing-engine" aria-label="Permalink to &quot;The Sizing Engine&quot;">​</a></h2><p><code>size-model.py</code> reads a GGUF file and computes the maximum safe context size for your specific hardware. The wizard calls this automatically. You can also run it standalone:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">python3</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> scripts/size-model.py</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /path/to/model.gguf</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --json</span></span></code></pre></div><p>Output includes:</p><ul><li><code>max_ctx</code> — maximum safe context window size</li><li><code>launch_flags</code> — optimal llama-server flags (GPU layers, KV cache type, MoE offloading, <code>--jinja</code>)</li><li><code>expert_flag</code> — MoE expert offloading flag (e.g. <code>--n-cpu-moe 25</code>)</li><li><code>headroom_gb</code> — VRAM safety margin</li><li><code>kv_gb</code> — KV cache memory estimate</li><li><code>cache_type_k</code> / <code>cache_type_v</code> — recommended KV cache quantization</li></ul><h2 id="regenerating-configs" tabindex="-1">Regenerating Configs <a class="header-anchor" href="#regenerating-configs" aria-label="Permalink to &quot;Regenerating Configs&quot;">​</a></h2><p>After adding new GGUF files to your models directory:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Backup existing config</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">cp</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> .env</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> .env.bak</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Regenerate everything (interactive)</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> run</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> setup</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Restart</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">docker</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> compose</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> restart</span></span></code></pre></div><p>Your model files are never touched. Only <code>.env</code> and <code>start-scripts/</code> are regenerated.</p>`,16)])])}const k=a(n,[["render",l]]);export{g as __pageData,k as default};
